                              </span>
                            </td>
                            <td><small>{new Date(u.created_at).toLocaleDateString()}</small></td>
                            <td>
                              {u.is_blocked
                                ? <span className="badge bg-danger">Blocked</span>
                                : <span className="badge bg-success">Active</span>}
