                            <td>
                              {u.role !== 'ADMIN' && (
                                <button className={`btn btn-sm ${u.is_blocked ? 'btn-success' : 'btn-outline-danger'}`}
                                  onClick={() => handleBlock(u.id)}>
                                  {u.is_blocked ? 'Unblock' : 'Block'}
                                </button>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}

                {/* Products Tab */}
                {activeTab === 'products' && (
                  <div className="table-responsive">
