                      <thead className="table-light">
                        <tr><th>Product</th><th>Seller</th><th>Starting</th><th>Current</th><th>Status</th><th>Action</th></tr>
                      </thead>
                      <tbody>
                        {products.map(p => (
                          <tr key={p.id}>
